40: // PluginManifest holds details for the file manifest
41: type PluginManifest struct {
42: 	Plugin  string            `json:"plugin"`
43: 	Version string            `json:"version"`
44: 	KeyID   string            `json:"keyId"`
45: 	Time    int64             `json:"time"`
46: 	Files   map[string]string `json:"files"`
47: 
48: 	// V2 supported fields
49: 	ManifestVersion string                `json:"manifestVersion"`
50: 	SignatureType   plugins.SignatureType `json:"signatureType"`
51: 	SignedByOrg     string                `json:"signedByOrg"`
52: 	SignedByOrgName string                `json:"signedByOrgName"`
53: 	RootURLs        []string              `json:"rootUrls"`
54: }
55: 
56: func (m *PluginManifest) IsV2() bool {
57: 	return strings.HasPrefix(m.ManifestVersion, "2.")
58: }
