17: 	return []ValidateFunc{
18: 		SignatureValidationStep(signature.NewValidator(signature.NewUnsignedAuthorizer(cfg))),
19: 		ModuleJSValidationStep(),
20: 		AngularDetectionStep(cfg, angularinspector.NewStaticInspector()),
21: 	}
