25: 	signatureValidator signature.Validator
26: 	log                log.Logger
27: }
28: 
29: func SignatureValidationStep(signatureValidator signature.Validator) ValidateFunc {
30: 	return newPluginSignatureValidator(signatureValidator).Validate
31: }
32: 
33: func newPluginSignatureValidator(signatureValidator signature.Validator) *PluginSignatureValidator {
34: 	return &PluginSignatureValidator{
35: 		signatureValidator: signatureValidator,
36: 		log:                log.New("plugins.validator.signature"),
37: 	}
