44: type ModuleJSValidator struct {
45: 	log log.Logger
46: }
47: 
48: func ModuleJSValidationStep() ValidateFunc {
49: 	return newModuleJSValidator().Validate
50: }
51: 
52: func newModuleJSValidator() *ModuleJSValidator {
53: 	return &ModuleJSValidator{
54: 		log: log.New("plugins.validator.module"),
55: 	}
56: }
57: 
58: func (v *ModuleJSValidator) Validate(_ context.Context, p *plugins.Plugin) error {
59: 	// CDN plugins are ignored because the module.js is guaranteed to exist
60: 	if p.Class == plugins.ClassCDN {
61: 		return nil
62: 	}
63: 
64: 	if !p.IsRenderer() && !p.IsCorePlugin() {
65: 		f, err := p.FS.Open("module.js")
66: 		if err != nil {
67: 			if errors.Is(err, plugins.ErrFileNotExist) {
68: 				v.log.Warn("Plugin missing module.js", "pluginId", p.ID,
69: 					"warning", "Missing module.js, If you loaded this plugin from git, make sure to compile it.")
70: 			}
71: 		} else if f != nil {
72: 			if err = f.Close(); err != nil {
73: 				v.log.Warn("Could not close module.js", "pluginId", p.ID, "error", err)
74: 			}
75: 		}
76: 	}
77: 	return nil
78: }
