80: type AngularDetector struct {
81: 	cfg              *config.PluginManagementCfg
82: 	angularInspector angularinspector.Inspector
83: 	log              log.Logger
84: }
85: 
86: func AngularDetectionStep(cfg *config.PluginManagementCfg, angularInspector angularinspector.Inspector) ValidateFunc {
87: 	return newAngularDetector(cfg, angularInspector).Validate
88: }
89: 
90: func newAngularDetector(cfg *config.PluginManagementCfg, angularInspector angularinspector.Inspector) *AngularDetector {
91: 	return &AngularDetector{
92: 		cfg:              cfg,
93: 		angularInspector: angularInspector,
94: 		log:              log.New("plugins.validator.angular"),
95: 	}
96: }
97: 
98: func (a *AngularDetector) Validate(ctx context.Context, p *plugins.Plugin) error {
99: 	if p.IsExternalPlugin() {
100: 		var err error
101: 
102: 		cctx, canc := context.WithTimeout(ctx, time.Second*10)
103: 		p.Angular.Detected, err = a.angularInspector.Inspect(cctx, p)
104: 		canc()
105: 
106: 		if err != nil {
107: 			a.log.Warn("Could not inspect plugin for angular", "pluginId", p.ID, "error", err)
108: 		}
109: 
110: 		// Do not initialize plugins if they're using Angular and Angular support is disabled
111: 		if p.Angular.Detected {
112: 			a.log.Error("Refusing to initialize plugin because it's using Angular, which has been disabled", "pluginId", p.ID)
113: 			return (&plugins.Error{
114: 				PluginID:  p.ID,
115: 				ErrorCode: plugins.ErrorAngular,
116: 			}).WithMessage("angular plugins are not supported")
117: 		}
118: 	}
119: 	return nil
120: }
