127: // ReportBuildMetrics reports build information for all plugins, except core plugins.
128: func ReportBuildMetrics(_ context.Context, p *plugins.Plugin) (*plugins.Plugin, error) {
129: 	if !p.IsCorePlugin() {
130: 		metrics.SetPluginBuildInformation(p.ID, string(p.Type), p.Info.Version, string(p.Signature))
131: 	}
132: 
