204: // SignatureValidation implements a ValidateFunc for validating plugin signatures.
205: type SignatureValidation struct {
206: 	signatureValidator signature.Validator
207: 	log                log.Logger
208: }
209: 
210: // SignatureValidationStep returns a new ValidateFunc for validating plugin signatures.
211: func SignatureValidationStep(signatureValidator signature.Validator) validation.ValidateFunc {
212: 	sv := &SignatureValidation{
213: 		signatureValidator: signatureValidator,
214: 		log:                log.New("plugins.signature.validation"),
215: 	}
