219: // Validate validates the plugin signature. If a signature error is encountered, the error is recorded with the
220: // pluginerrs.ErrorTracker.
221: func (v *SignatureValidation) Validate(ctx context.Context, p *plugins.Plugin) error {
222: 	err := v.signatureValidator.ValidateSignature(p)
223: 	if err != nil {
224: 		var sigErr *plugins.Error
225: 		if errors.As(err, &sigErr) {
226: 			v.log.Warn("Skipping loading plugin due to problem with signature",
227: 				"pluginId", p.ID, "status", sigErr.SignatureStatus)
228: 			p.Error = sigErr
229: 		}
230: 		return err
231: 	}
232: 
233: 	return nil
234: }
