272: // AsExternal is a filter step that will skip loading a core plugin to use an external one.
273: type AsExternal struct {
274: 	log log.Logger
275: 	cfg *config.PluginManagementCfg
276: }
277: 
278: // NewAsExternalStep returns a new DisablePlugins.
279: func NewAsExternalStep(cfg *config.PluginManagementCfg) *AsExternal {
280: 	return &AsExternal{
281: 		cfg: cfg,
282: 		log: log.New("plugins.asExternal"),
283: 	}
284: }
285: 
286: // Filter will filter out any plugins that are marked to be disabled.
287: func (c *AsExternal) Filter(cl plugins.Class, bundles []*plugins.FoundBundle) ([]*plugins.FoundBundle, error) {
288: 	if cl == plugins.ClassCore {
289: 		res := []*plugins.FoundBundle{}
290: 		for _, bundle := range bundles {
291: 			pluginCfg := c.cfg.PluginSettings[bundle.Primary.JSONData.ID]
292: 			// Skip core plugins if the feature flag is enabled and the plugin is in the skip list.
293: 			// It could be loaded later as an external plugin.
294: 			if pluginCfg["as_external"] == "true" {
295: 				c.log.Debug("Skipping the core plugin load", "pluginID", bundle.Primary.JSONData.ID)
296: 			} else {
297: 				res = append(res, bundle)
298: 			}
299: 		}
300: 		return res, nil
301: 	}
302: 	return bundles, nil
303: }
