305: // DuplicatePluginIDValidation is a filter step that will filter out any plugins that are already registered with the same
306: // plugin ID. This includes both the primary plugin and child plugins, which are matched using the plugin.json plugin
307: // ID field.
308: type DuplicatePluginIDValidation struct {
309: 	registry registry.Service
310: 	log      log.Logger
311: }
312: 
313: // NewDuplicatePluginIDFilterStep returns a new DuplicatePluginIDValidation.
314: func NewDuplicatePluginIDFilterStep(registry registry.Service) *DuplicatePluginIDValidation {
315: 	return &DuplicatePluginIDValidation{
316: 		registry: registry,
317: 		log:      log.New("plugins.dedupe"),
318: 	}
319: }
320: 
321: // Filter will filter out any plugins that have already been registered under the same plugin ID.
322: func (d *DuplicatePluginIDValidation) Filter(ctx context.Context, bundles []*plugins.FoundBundle) ([]*plugins.FoundBundle, error) {
323: 	res := make([]*plugins.FoundBundle, 0, len(bundles))
324: 
325: 	var matchesPluginIDFunc = func(fp plugins.FoundPlugin) func(p *plugins.Plugin) bool {
326: 		return func(p *plugins.Plugin) bool {
327: 			return p.ID == fp.JSONData.ID
328: 		}
329: 	}
330: 
331: 	for _, b := range bundles {
332: 		ps := d.registry.Plugins(ctx)
333: 
334: 		if slices.ContainsFunc(ps, matchesPluginIDFunc(b.Primary)) {
335: 			d.log.Warn("Skipping loading of plugin as it's a duplicate", "pluginId", b.Primary.JSONData.ID)
336: 			continue
337: 		}
338: 
339: 		var nonDupeChildren []*plugins.FoundPlugin
340: 		for _, child := range b.Children {
341: 			if slices.ContainsFunc(ps, matchesPluginIDFunc(*child)) {
342: 				d.log.Warn("Skipping loading of child plugin as it's a duplicate", "pluginId", child.JSONData.ID)
343: 				continue
344: 			}
345: 			nonDupeChildren = append(nonDupeChildren, child)
346: 		}
347: 		res = append(res, &plugins.FoundBundle{
348: 			Primary:  b.Primary,
349: 			Children: nonDupeChildren,
350: 		})
351: 	}
352: 
353: 	return res, nil
354: }
